import React from 'react';
import { TodoList } from './TodoList';
import type { Todo, TodoApi } from './TodoList';

const INITIAL: Todo[] = [
  { id: '1', text: 'Buy groceries', completed: false },
  { id: '2', text: 'Read a book', completed: true },
  { id: '3', text: 'Go for a walk', completed: false },
];

/** Simulated API — resolves after a delay, randomly fails 30% of the time */
const api: TodoApi = {
  addTodo: (text) =>
    new Promise((resolve, reject) =>
      setTimeout(() => {
        if (Math.random() < 0.3) reject(new Error('Failed to add'));
        else resolve({ id: Date.now().toString(), text, completed: false });
      }, 800)
    ),
  toggleTodo: (id) =>
    new Promise((resolve, reject) =>
      setTimeout(() => {
        if (Math.random() < 0.3) reject(new Error('Failed to toggle'));
        else resolve();
      }, 600)
    ),
  deleteTodo: (id) =>
    new Promise((resolve, reject) =>
      setTimeout(() => {
        if (Math.random() < 0.3) reject(new Error('Failed to delete'));
        else resolve();
      }, 600)
    ),
};

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Optimistic Todos</h1>
      <TodoList initialTodos={INITIAL} api={api} />
    </div>
  );
}

import React, { useState } from 'react';
import './styles.css';

export interface Todo {
  id: string;
  text: string;
  completed: boolean;
}

export interface TodoApi {
  addTodo: (text: string) => Promise<Todo>;
  toggleTodo: (id: string) => Promise<void>;
  deleteTodo: (id: string) => Promise<void>;
}

interface TodoListProps {
  initialTodos: Todo[];
  api: TodoApi;
}

export const TodoList: React.FC<TodoListProps> = ({ initialTodos, api }) => {
  const [todos, setTodos] = useState<Todo[]>(initialTodos);
  const [input, setInput] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [pending, setPending] = useState<Set<string>>(new Set());

  // TODO: Implement optimistic add
  const handleAdd = () => {};

  // TODO: Implement optimistic toggle
  const handleToggle = (id: string) => {};

  // TODO: Implement optimistic delete
  const handleDelete = (id: string) => {};

  return (
    <div className="todo">
      {error && (
        <div data-testid="error-toast" className="todo__toast">
          {error}
        </div>
      )}

      <div className="todo__add">
        <input
          data-testid="todo-input"
          className="todo__input"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Add a todo…"
        />
        <button
          data-testid="todo-add"
          className="todo__btn todo__btn--add"
          onClick={handleAdd}
        >
          Add
        </button>
      </div>

      <ul className="todo__list">
        {todos.map((todo, i) => (
          <li
            key={todo.id}
            data-testid={`todo-item-${i}`}
            className={`todo__item${
              todo.completed ? ' todo__item--done' : ''
            }${pending.has(todo.id) ? ' todo__item--pending' : ''}`}
          >
            <span className="todo__text">{todo.text}</span>
            <button
              data-testid={`todo-toggle-${i}`}
              className="todo__btn todo__btn--toggle"
              onClick={() => handleToggle(todo.id)}
            >
              {todo.completed ? '✓' : '○'}
            </button>
            <button
              data-testid={`todo-delete-${i}`}
              className="todo__btn todo__btn--delete"
              onClick={() => handleDelete(todo.id)}
            >
              ✕
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default TodoList;

.todo {
  max-width: 28rem;
  position: relative;
}

.todo__toast {
  position: absolute;
  top: -2.5rem;
  left: 0;
  right: 0;
  background: #fee2e2;
  color: #991b1b;
  padding: 0.5rem 0.75rem;
  border-radius: 0.375rem;
  font-size: 0.8125rem;
  animation: slideIn 0.2s ease;
}

@keyframes slideIn {
  from { opacity: 0; transform: translateY(-0.5rem); }
  to { opacity: 1; transform: translateY(0); }
}

.todo__add {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1rem;
}

.todo__input {
  flex: 1;
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  outline: none;
}

.todo__input:focus {
  border-color: #3b82f6;
  box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.15);
}

.todo__list {
  list-style: none;
  padding: 0;
  margin: 0;
  border: 1px solid #e5e7eb;
  border-radius: 0.375rem;
  overflow: hidden;
}

.todo__item {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.625rem 0.75rem;
  transition: opacity 0.2s ease;
}

.todo__item + .todo__item {
  border-top: 1px solid #f3f4f6;
}

.todo__item--pending {
  opacity: 0.6;
}

.todo__item--done .todo__text {
  text-decoration: line-through;
  color: #9ca3af;
}

.todo__text {
  flex: 1;
  font-size: 0.875rem;
  color: #374151;
}

.todo__btn {
  padding: 0.25rem 0.5rem;
  border: 1px solid #d1d5db;
  border-radius: 0.25rem;
  background: white;
  cursor: pointer;
  font-size: 0.75rem;
  transition: all 0.1s ease;
}

.todo__btn--add {
  background: #3b82f6;
  color: white;
  border-color: #3b82f6;
}

.todo__btn--add:hover { background: #2563eb; }

.todo__btn--toggle:hover {
  background: #eff6ff;
  border-color: #93c5fd;
}

.todo__btn--delete:hover {
  background: #fef2f2;
  border-color: #fca5a5;
  color: #dc2626;
}

