import { render, screen, fireEvent, waitFor, act } from '@testing-library/react';
import '@testing-library/jest-dom';
import { TodoList } from './TodoList';
import type { Todo, TodoApi } from './TodoList';

const TODOS: Todo[] = [
  { id: '1', text: 'Task A', completed: false },
  { id: '2', text: 'Task B', completed: false },
];

const successApi: TodoApi = {
  addTodo: (text) => Promise.resolve({ id: '99', text, completed: false }),
  toggleTodo: () => Promise.resolve(),
  deleteTodo: () => Promise.resolve(),
};

const failApi: TodoApi = {
  addTodo: () => Promise.reject(new Error('Add failed')),
  toggleTodo: () => Promise.reject(new Error('Toggle failed')),
  deleteTodo: () => Promise.reject(new Error('Delete failed')),
};

describe('TodoList — Optimistic Updates', () => {
  it('renders initial todos', () => {
    render(<TodoList initialTodos={TODOS} api={successApi} />);
    expect(screen.getByTestId('todo-item-0')).toHaveTextContent('Task A');
    expect(screen.getByTestId('todo-item-1')).toHaveTextContent('Task B');
  });

  it('optimistically adds a new todo', async () => {
    render(<TodoList initialTodos={TODOS} api={successApi} />);
    fireEvent.change(screen.getByTestId('todo-input'), { target: { value: 'New' } });
    fireEvent.click(screen.getByTestId('todo-add'));
    expect(screen.getByText('New')).toBeInTheDocument();
  });

  it('optimistically toggles a todo', async () => {
    render(<TodoList initialTodos={TODOS} api={successApi} />);
    fireEvent.click(screen.getByTestId('todo-toggle-0'));
    expect(screen.getByTestId('todo-item-0')).toHaveClass('todo__item--done');
  });

  it('optimistically deletes a todo', async () => {
    render(<TodoList initialTodos={TODOS} api={successApi} />);
    fireEvent.click(screen.getByTestId('todo-delete-0'));
    expect(screen.queryByText('Task A')).not.toBeInTheDocument();
  });

  it('reverts add on API failure and shows error', async () => {
    render(<TodoList initialTodos={TODOS} api={failApi} />);
    fireEvent.change(screen.getByTestId('todo-input'), { target: { value: 'Bad' } });
    fireEvent.click(screen.getByTestId('todo-add'));
    expect(screen.getByText('Bad')).toBeInTheDocument();
    await waitFor(() => {
      expect(screen.queryByText('Bad')).not.toBeInTheDocument();
    });
    expect(screen.getByTestId('error-toast')).toBeInTheDocument();
  });

  it('reverts toggle on API failure', async () => {
    render(<TodoList initialTodos={TODOS} api={failApi} />);
    fireEvent.click(screen.getByTestId('todo-toggle-0'));
    expect(screen.getByTestId('todo-item-0')).toHaveClass('todo__item--done');
    await waitFor(() => {
      expect(screen.getByTestId('todo-item-0')).not.toHaveClass('todo__item--done');
    });
  });

  it('marks pending items with pending class', () => {
    const slowApi: TodoApi = {
      ...successApi,
      toggleTodo: () => new Promise(() => {}),
    };
    render(<TodoList initialTodos={TODOS} api={slowApi} />);
    fireEvent.click(screen.getByTestId('todo-toggle-0'));
    expect(screen.getByTestId('todo-item-0')).toHaveClass('todo__item--pending');
  });
});

