import React, { useState, useCallback, useRef } from 'react';
import './styles.css';

export interface Todo {
  id: string;
  text: string;
  completed: boolean;
}

export interface TodoApi {
  addTodo: (text: string) => Promise<Todo>;
  toggleTodo: (id: string) => Promise<void>;
  deleteTodo: (id: string) => Promise<void>;
}

interface TodoListProps {
  initialTodos: Todo[];
  api: TodoApi;
}

let tempId = 0;

export const TodoList: React.FC<TodoListProps> = ({ initialTodos, api }) => {
  const [todos, setTodos] = useState<Todo[]>(initialTodos);
  const [input, setInput] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [pending, setPending] = useState<Set<string>>(new Set());
  const toastTimer = useRef<ReturnType<typeof setTimeout>>();

  const showError = (msg: string) => {
    setError(msg);
    clearTimeout(toastTimer.current);
    toastTimer.current = setTimeout(() => setError(null), 3000);
  };

  const markPending = (id: string) =>
    setPending((s) => new Set(s).add(id));
  const unmarkPending = (id: string) =>
    setPending((s) => { const n = new Set(s); n.delete(id); return n; });

  const handleAdd = useCallback(() => {
    const text = input.trim();
    if (!text) return;
    const tmpId = `__tmp_${++tempId}`;
    const optimistic: Todo = { id: tmpId, text, completed: false };
    const snapshot = [...todos];
    setTodos((t) => [...t, optimistic]);
    setInput('');
    markPending(tmpId);

    api.addTodo(text)
      .then((real) => {
        setTodos((t) => t.map((item) => (item.id === tmpId ? real : item)));
      })
      .catch((err) => {
        setTodos(snapshot);
        showError(err.message || 'Failed to add');
      })
      .finally(() => unmarkPending(tmpId));
  }, [input, todos, api]);

  const handleToggle = useCallback(
    (id: string) => {
      const snapshot = [...todos];
      setTodos((t) =>
        t.map((item) =>
          item.id === id ? { ...item, completed: !item.completed } : item
        )
      );
      markPending(id);

      api.toggleTodo(id)
        .catch((err) => {
          setTodos(snapshot);
          showError(err.message || 'Failed to toggle');
        })
        .finally(() => unmarkPending(id));
    },
    [todos, api]
  );

  const handleDelete = useCallback(
    (id: string) => {
      const snapshot = [...todos];
      setTodos((t) => t.filter((item) => item.id !== id));
      markPending(id);

      api.deleteTodo(id)
        .catch((err) => {
          setTodos(snapshot);
          showError(err.message || 'Failed to delete');
        })
        .finally(() => unmarkPending(id));
    },
    [todos, api]
  );

  return (
    <div className="todo">
      {error && (
        <div data-testid="error-toast" className="todo__toast">
          {error}
        </div>
      )}

      <div className="todo__add">
        <input
          data-testid="todo-input"
          className="todo__input"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Add a todo…"
          onKeyDown={(e) => e.key === 'Enter' && handleAdd()}
        />
        <button
          data-testid="todo-add"
          className="todo__btn todo__btn--add"
          onClick={handleAdd}
        >
          Add
        </button>
      </div>

      <ul className="todo__list">
        {todos.map((todo, i) => (
          <li
            key={todo.id}
            data-testid={`todo-item-${i}`}
            className={`todo__item${
              todo.completed ? ' todo__item--done' : ''
            }${pending.has(todo.id) ? ' todo__item--pending' : ''}`}
          >
            <span className="todo__text">{todo.text}</span>
            <button
              data-testid={`todo-toggle-${i}`}
              className="todo__btn todo__btn--toggle"
              onClick={() => handleToggle(todo.id)}
            >
              {todo.completed ? '\u2713' : '\u25CB'}
            </button>
            <button
              data-testid={`todo-delete-${i}`}
              className="todo__btn todo__btn--delete"
              onClick={() => handleDelete(todo.id)}
            >
              \u2715
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default TodoList;
